    "home.process.step1.title": { en: "We read your site<br><em>like a lost lead would.</em>", pt: "Lemos seu site<br><em>como um lead perdido leria.</em>" },
    "home.process.step1.desc": { en: "Before we touch a pixel, we map where your site loses attention. Conversion blockers, buried trust signals, form friction, slow loads. You get a prioritized list of what's actually costing you leads.", pt: "Antes de tocar em um pixel, mapeamos onde seu site perde atenção. Bloqueios de conversão, sinais de confiança escondidos, atrito em formulários, carregamento lento. Você recebe uma lista priorizada do que está realmente custando seus leads." },
    "home.process.step1.delivery": { en: "Delivery: 48h audit report", pt: "Entrega: relatório de auditoria em 48h" },
    "home.process.step2.title": { en: "You approve<br><em>a concrete plan.</em>", pt: "Você aprova<br><em>um plano concreto.</em>" },
    "home.process.step2.desc": { en: "We turn the audit into a tight scope. What gets fixed first for the fastest impact, what gets restructured, and what gets cut. One document, no ambiguity. You sign off before we write a line of code.", pt: "Transformamos a auditoria em um escopo objetivo. O que é corrigido primeiro para o impacto mais rápido, o que é reestruturado e o que é cortado. Um documento, sem ambiguidade. Você aprova antes de escrevermos uma linha de código." },
    "home.process.step2.delivery": { en: "Delivery: Action plan + timeline, within 3 days", pt: "Entrega: plano de ação + cronograma, em até 3 dias" },
    "home.process.step3.title": { en: "We build it<br><em>without the noise.</em>", pt: "Construímos<br><em>sem o ruído.</em>" },
    "home.process.step3.desc": { en: "Design, copy, and engineering run in parallel. We don't drag you into endless feedback loops. We show you work when there's something real to review. Every decision ties back to the brief, not personal taste.", pt: "Design, copy e engenharia rodam em paralelo. Não te arrastamos para loops infinitos de feedback. Mostramos o trabalho quando há algo real para revisar. Cada decisão volta ao briefing, não ao gosto pessoal." },
    "home.process.step3.delivery": { en: "Delivery: Staging environment, week 2 to 3", pt: "Entrega: ambiente de homologação, semana 2 a 3" },
    "home.process.step4.title": { en: "We ship, and you<br><em>can actually measure it.</em>", pt: "Lançamos, e você<br><em>consegue medir de verdade.</em>" },
    "home.process.step4.desc": { en: "Launch comes with tracking already configured. Session heatmaps, conversion events, form completion rates. You'll know within the first week if the site is pulling its weight.", pt: "O lançamento já vem com rastreamento configurado. Mapas de calor de sessão, eventos de conversão, taxas de conclusão de formulário. Você vai saber na primeira semana se o site está performando." },
    "home.process.step4.delivery": { en: "Delivery: Live site + analytics setup, week 4 to 5", pt: "Entrega: site no ar + configuração de analytics, semana 4 a 5" },
    "home.process.cta.title": { en: "Most sites lose the lead<br><em class=\"text-vw-accent\">before a single word gets read.</em>", pt: "A maioria dos sites perde o lead<br><em class=\"text-vw-accent\">antes que uma única palavra seja lida.</em>" },
    "home.process.cta.desc": { en: "The diagnosis takes 15 minutes. You'll leave knowing exactly what's costing you leads. No charge.", pt: "O diagnóstico leva 15 minutos. Você vai saber exatamente o que está te custando leads. Sem custo." },
