    "work.consistent.title": { en: "What stays consistent<br><em class=\"text-vw-accent\">across projects.</em>", pt: "O que se mantém<br><em class=\"text-vw-accent\">em todos os projetos.</em>" },
    "work.consistent.subtitle": { en: "Different industries, different audiences, different starting points. The framework underneath stays the same because conversion problems follow the same patterns regardless of sector.", pt: "Indústrias diferentes, públicos diferentes, pontos de partida diferentes. O framework por trás permanece o mesmo porque problemas de conversão seguem os mesmos padrões independente do setor." },
    "work.pillar1.title": { en: "Audit before a pixel moves", pt: "Auditoria antes de qualquer pixel" },
    "work.pillar1.desc": { en: "We map where leads are leaking before proposing any solution. The diagnosis dictates the scope. Not the other way around. Every decision that follows comes from data, not instinct.", pt: "Mapeamos onde os leads estão vazando antes de propor qualquer solução. O diagnóstico dita o escopo. Não o contrário. Toda decisão seguinte vem de dados, não de instinto." },
    "work.pillar2.title": { en: "Proof placed at decision points", pt: "Prova posicionada nos pontos de decisão" },
    "work.pillar2.desc": { en: "Reviews, credentials and results go where hesitation lives. Not in a generic footer block nobody scrolls to. Trust is architected into the page structure.", pt: "Avaliações, credenciais e resultados ficam onde a hesitação mora. Não em um bloco genérico de rodapé que ninguém rola até. A confiança é arquitetada na estrutura da página." },
    "work.pillar3.title": { en: "One clear path to the CTA", pt: "Um caminho claro até o CTA" },
    "work.pillar3.desc": { en: "Every page has a primary action. Secondary options exist but they do not compete. Hierarchy is enforced, not suggested. Visitors are guided, not asked to choose.", pt: "Cada página tem uma ação primária. Opções secundárias existem, mas não competem. A hierarquia é imposta, não sugerida. Os visitantes são guiados, não convidados a escolher." },
    "work.pillar4.title": { en: "Tracking built into launch", pt: "Rastreamento integrado ao lançamento" },
    "work.pillar4.desc": { en: "GA4 events, session heat maps, form completion rates. All configured before go-live so you know within week one what is working. No guessing after ship.", pt: "Eventos do GA4, mapas de calor de sessão, taxas de conclusão de formulário. Tudo configurado antes do lançamento para você saber na primeira semana o que está funcionando. Sem achismo depois de lançar." },
    "work.consistent.cta1": { en: "See our process", pt: "Ver nosso processo" },
    "work.consistent.cta2": { en: "Get a free diagnosis", pt: "Peça um diagnóstico gratuito" },

    // ── Work page: CTA strip ──
    "work.ctastrip.title": { en: "Want results<br><em class=\"text-vw-accent\">like these?</em>", pt: "Quer resultados<br><em class=\"text-vw-accent\">como esses?</em>" },
    "work.ctastrip.desc": { en: "We'll read your current site live, flag what's blocking conversions, and map out what to fix first. You keep the diagnosis either way.", pt: "Vamos analisar seu site atual em tempo real, apontar o que está bloqueando conversões e mapear o que corrigir primeiro. Você fica com o diagnóstico de qualquer jeito." },
    "work.ctastrip.note": { en: "Clear next steps within 24h. No spam.", pt: "Próximos passos claros em até 24h. Sem spam." },

    // ── Packages page: Hero ──
    "packages.hero.eyebrow": { en: "[ PACKAGES ] <span class=\"w-1.5 h-6 bg-vw-accent inline-block\"></span>", pt: "[ PLANOS ] <span class=\"w-1.5 h-6 bg-vw-accent inline-block\"></span>" },
    "packages.hero.title": { en: "Clear scope.<br><em class=\"text-vw-accent\">Honest pricing.</em>", pt: "Escopo claro.<br><em class=\"text-vw-accent\">Preço honesto.</em>" },
    "packages.hero.subtitle": { en: "No hourly billing. No scope creep. Every package is scoped to your specific conversion problem and priced before we start.", pt: "Sem cobrança por hora. Sem escopo que cresce sozinho. Cada pacote é desenhado para o seu problema de conversão específico e precificado antes de começarmos." },
    "packages.hero.social": { en: "47 projects shipped in 2025", pt: "47 projetos entregues em 2025" },

