    // ── Studio page ──
    "studio.hero.eyebrow": { en: "[ STUDIO ] <span class=\"w-1.5 h-6 bg-vw-accent inline-block\"></span>", pt: "[ ESTÚDIO ] <span class=\"w-1.5 h-6 bg-vw-accent inline-block\"></span>" },
    "studio.hero.title": { en: "A small team that<br><em class=\"text-vw-accent\">ships fast and measures everything.</em>", pt: "Um time pequeno que<br><em class=\"text-vw-accent\">entrega rápido e mede tudo.</em>" },
    "studio.hero.subtitle": { en: "No account managers. No layers. You talk to the people who design, write, and build your site. They're the same people who read your analytics after launch.", pt: "Sem gerentes de conta. Sem camadas. Você fala com as pessoas que desenham, escrevem e constroem seu site. São as mesmas pessoas que leem seus analytics depois do lançamento." },
    "studio.hero.location": { en: "Curitiba, Paraná, BR", pt: "Curitiba, Paraná, BR" },
    "studio.hero.est": { en: "Est. 2024", pt: "Fundada em 2024" },

