    // ── Terms of Use page ──
    "terms.eyebrow": { en: "[ Legal ] <span class=\"w-1.5 h-6 bg-vw-accent inline-block\"></span>", pt: "[ Jurídico ] <span class=\"w-1.5 h-6 bg-vw-accent inline-block\"></span>" },
    "terms.title": { en: "Terms of <span class=\"text-vw-accent\">Use</span>", pt: "Termos de <span class=\"text-vw-accent\">Uso</span>" },
    "terms.updated": { en: "Last updated: May 2026", pt: "Última atualização: maio de 2026" },
    "terms.h1": { en: "1. Acceptance of Terms", pt: "1. Aceitação dos Termos" },
    "terms.p1": { en: "By accessing or using the Vellumwire website and services, you agree to be bound by these Terms of Use. If you do not agree with any part of these terms, you must not use our website or services.", pt: "Ao acessar ou usar o site e os serviços da Vellumwire, você concorda em ficar vinculado a estes Termos de Uso. Se você não concordar com qualquer parte destes termos, não deve usar nosso site ou serviços." },
    "terms.h2": { en: "2. Services Description", pt: "2. Descrição dos Serviços" },
    "terms.p2": { en: "Vellumwire provides web design, development, and digital strategy services. The specifics of each engagement are outlined in a separate agreement or proposal. These Terms of Use govern your use of our website, while service-specific terms are defined in individual contracts.", pt: "A Vellumwire oferece serviços de web design, desenvolvimento e estratégia digital. Os detalhes de cada projeto são definidos em um acordo ou proposta separada. Estes Termos de Uso regem o uso do nosso site, enquanto os termos específicos de serviço são definidos em contratos individuais." },
    "terms.h3": { en: "3. Intellectual Property", pt: "3. Propriedade Intelectual" },
    "terms.p3a": { en: "All content on this website including text, graphics, logos, code, and visual designs is the property of Vellumwire unless otherwise stated. You may not reproduce, distribute, modify, or republish any content without our prior written consent.", pt: "Todo o conteúdo deste site, incluindo textos, gráficos, logos, código e designs visuais, é propriedade da Vellumwire, salvo indicação em contrário. Você não pode reproduzir, distribuir, modificar ou republicar qualquer conteúdo sem nosso consentimento prévio por escrito." },
    "terms.p3b": { en: "Upon full payment for services, clients receive the rights to the deliverables specified in their agreement. Vellumwire retains the right to display work in our portfolio unless otherwise agreed in writing.", pt: "Após o pagamento integral dos serviços, os clientes recebem os direitos sobre as entregas especificadas em seu contrato. A Vellumwire mantém o direito de exibir o trabalho em nosso portfólio, salvo acordo em contrário por escrito." },
    "terms.h4": { en: "4. User Conduct", pt: "4. Conduta do Usuário" },
    "terms.p4": { en: "You agree not to:", pt: "Você concorda em não:" },
    "terms.li4_1": { en: "Use our website for any unlawful purpose.", pt: "Usar nosso site para qualquer finalidade ilegal." },
    "terms.li4_2": { en: "Attempt to gain unauthorized access to our systems.", pt: "Tentar obter acesso não autorizado aos nossos sistemas." },
    "terms.li4_3": { en: "Interfere with the proper functioning of the website.", pt: "Interferir no funcionamento adequado do site." },
    "terms.li4_4": { en: "Submit false or misleading information through our contact forms.", pt: "Enviar informações falsas ou enganosas pelos nossos formulários de contato." },
    "terms.h5": { en: "5. Limitation of Liability", pt: "5. Limitação de Responsabilidade" },
    "terms.p5": { en: "Vellumwire shall not be liable for any indirect, incidental, or consequential damages arising from your use of our website or services. Our total liability is limited to the amount paid by you for the specific service giving rise to the claim.", pt: "A Vellumwire não será responsável por quaisquer danos indiretos, incidentais ou consequenciais decorrentes do uso do nosso site ou serviços. Nossa responsabilidade total é limitada ao valor pago por você pelo serviço específico que originou a reclamação." },
    "terms.h6": { en: "6. Third-Party Tools", pt: "6. Ferramentas de Terceiros" },
    "terms.p6": { en: "Our website may integrate with third-party tools and services (e.g., analytics, hosting, payment processors). We do not control these third parties and are not responsible for their actions. Your use of such services is subject to their respective terms.", pt: "Nosso site pode integrar ferramentas e serviços de terceiros (por exemplo, analytics, hospedagem, processadores de pagamento). Não controlamos esses terceiros e não somos responsáveis por suas ações. O uso desses serviços está sujeito aos respectivos termos deles." },
    "terms.h7": { en: "7. Confidentiality", pt: "7. Confidencialidade" },
    "terms.p7": { en: "We treat all client information shared during the course of a project as confidential. Vellumwire will not disclose confidential information to third parties except as necessary to deliver services or as required by law.", pt: "Tratamos todas as informações do cliente compartilhadas durante um projeto como confidenciais. A Vellumwire não divulgará informações confidenciais a terceiros, exceto quando necessário para a prestação dos serviços ou conforme exigido por lei." },
    "terms.h8": { en: "8. Termination", pt: "8. Rescisão" },
    "terms.p8": { en: "We reserve the right to refuse service, suspend access, or terminate engagements for violations of these terms or for conduct we deem harmful to our business or other clients.", pt: "Reservamo-nos o direito de recusar serviço, suspender o acesso ou encerrar projetos em caso de violação destes termos ou de conduta que consideremos prejudicial ao nosso negócio ou a outros clientes." },
    "terms.h9": { en: "9. Governing Law", pt: "9. Lei Aplicável" },
    "terms.p9": { en: "These Terms of Use are governed by the laws of Brazil, specifically the state of Paraná. Any disputes shall be resolved in the courts of Curitiba, Paraná.", pt: "Estes Termos de Uso são regidos pelas leis do Brasil, especificamente do estado do Paraná. Quaisquer disputas serão resolvidas nos tribunais de Curitiba, Paraná." },
    "terms.h10": { en: "10. Changes to Terms", pt: "10. Alterações nos Termos" },
    "terms.p10": { en: "We may update these Terms of Use at any time. Changes are effective immediately upon posting. Continued use of our website after changes constitutes acceptance of the new terms.", pt: "Podemos atualizar estes Termos de Uso a qualquer momento. As alterações entram em vigor imediatamente após a publicação. O uso contínuo do nosso site após as alterações constitui aceitação dos novos termos." },
    "terms.h11": { en: "11. Contact", pt: "11. Contato" },
    "terms.email_label": { en: "Email:", pt: "E-mail:" },
